using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Core;

namespace TowerDefense.Enemy
{
    [RequireComponent(typeof(EnemyMovement), typeof(EnemyHealth))]
    public class Enemy : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private EnemyData _enemyData;

        [Header("Health Bar")]
        [SerializeField] private Slider _healthSlider;
        [SerializeField] private Image _healthFillImage;
        [SerializeField] private Color _lowHealthColor = Color.red;
        [SerializeField] private Color _mediumHealthColor = Color.yellow;
        [SerializeField] private Color _highHealthColor = Color.green;
        [SerializeField] private float _healthBarOffsetY = 1.5f;

        private EnemyMovement _movement;
        private EnemyHealth _health;
        private Canvas _healthCanvas;

        public EnemyData Data => _enemyData;
        public EnemyMovement Movement => _movement;
        public EnemyHealth Health => _health;
        public bool IsDead => _health != null && _health.CurrentHealth <= 0;

        private int _birthWaveId = -1;  // 敌人归属的波次ID

        // 给 EnemySpawner 调用的
        public void SetBirthWaveId(int waveId)
        {
            _birthWaveId = waveId;
        }

        private void Awake()
        {
            _movement = GetComponent<EnemyMovement>();
            _health = GetComponent<EnemyHealth>();

            // 获取血条画布
            if (_healthSlider != null)
            {
                _healthCanvas = _healthSlider.GetComponentInParent<Canvas>();
                _healthSlider.value = 1f;
            }

            if (_enemyData != null)
            {
                Initialize(_enemyData);
            }
        }

        public void Initialize(EnemyData data)
        {
            _enemyData = data;

            if (_health != null)
            {
                _health.Initialize(data.stats.maxHealth, data.stats.goldReward);
                _health.OnHealthChanged += UpdateHealthBar;
                _health.OnDeath += OnDeath;
            }

            if (_movement != null)
            {
                _movement.SetSpeed(data.stats.moveSpeed);
            }

            // 初始化血条
            UpdateHealthBar(data.stats.maxHealth, data.stats.maxHealth);
        }

        public void StartMovement(PathCreator pathCreator)
        {
            if (_movement != null)
            {
                _movement.FollowPath(pathCreator);
            }
        }

        public void OnReachedEnd()
        {
            // 敌人走到终点也统计为波次敌人不再场
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            if (GameManager.Instance != null)
            {
                GameManager.Instance.TakeDamage(_enemyData.stats.lifeDamage);
            }
            EventBus.Publish(new EnemyReachEndEvent { Enemy = gameObject, Damage = _enemyData.stats.lifeDamage });
            Destroy(gameObject);
        }

        public void OnDeath()
        {
            // 波次统计-带上GameObject给HashSet去重
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            // 解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }

            // 隐藏血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = false;
            }

            if (GameManager.Instance != null)
            {
                GameManager.Instance.AddGold(_enemyData.stats.goldReward);
                GameManager.Instance.AddKill();
            }
            EventBus.Publish(new EnemyDeathEvent { Enemy = gameObject, Reward = _enemyData.stats.goldReward });
            Destroy(gameObject);
        }

        private void Update()
        {
            // 更新血条位置，始终在敌人头顶
            UpdateHealthBarPosition();
        }

        private void UpdateHealthBar(int currentHealth, int maxHealth)
        {
            if (_healthSlider == null) return;

            float healthPercent = (float)currentHealth / maxHealth;
            _healthSlider.value = healthPercent;

            // 根据血量改变颜色
            UpdateHealthBarColor(healthPercent);

            // 当血量低于最大值时显示血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = healthPercent < 1f;
            }
        }

        private void UpdateHealthBarColor(float healthPercent)
        {
            if (_healthFillImage == null) return;

            if (healthPercent <= 0.3f)
            {
                _healthFillImage.color = _lowHealthColor;
            }
            else if (healthPercent <= 0.6f)
            {
                _healthFillImage.color = _mediumHealthColor;
            }
            else
            {
                _healthFillImage.color = _highHealthColor;
            }
        }

        private void UpdateHealthBarPosition()
        {
            if (_healthSlider == null || _healthCanvas == null) return;

            // 将世界坐标转换为屏幕坐标
            Vector3 worldPosition = transform.position;
            worldPosition.y += _healthBarOffsetY;

            // 如果是世界空间画布，直接设置位置
            if (_healthCanvas.renderMode == RenderMode.WorldSpace)
            {
                _healthSlider.transform.position = worldPosition;
            }
            else
            {
                // 如果是屏幕空间画布，转换坐标
                Vector3 screenPosition = Camera.main.WorldToScreenPoint(worldPosition);
                _healthSlider.transform.position = screenPosition;
            }
        }

        private void OnDestroy()
        {
            // 确保解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }
        }

        public void TakeDamage(int damage)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage);
            }
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage, damageType);
            }
        }

        public void ApplySlow(float slowFactor, float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(slowFactor, duration);
            }
        }

        public void ApplyStun(float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(0f, duration);
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Hero
{
    public enum HeroState
    {
        Idle,
        Moving,
        Attacking,
        UsingSkill,
        Dead
    }

    public class Hero : MonoBehaviour
    {
        [Header("Data")]
        [SerializeField] private HeroData _heroData;

        [Header("Components")]
        [SerializeField] private Animator _animator;
        [SerializeField] private SpriteRenderer _spriteRenderer;
        [SerializeField] private Transform _healthBarAnchor;

        [Header("Movement")]
        [SerializeField] private float _moveSpeed = 3f;
        [SerializeField] private float _arrivalThreshold = 0.2f;

        private HeroState _currentState = HeroState.Idle;
        private HeroData.HeroStats _currentStats;
        private float _currentHealth;
        private int _currentLevel = 1;
        private float _currentExp = 0f;
        private float _expToNextLevel = 100f;

        private Enemy.Enemy _currentTarget;
        private Vector3 _targetPosition;
        private bool _isMoving = false;
        private float _attackCooldown = 0f;

        private Dictionary<string, float> _skillCooldowns = new Dictionary<string, float>();

        public HeroData Data => _heroData;
        public HeroState State => _currentState;
        public int CurrentLevel => _currentLevel;
        public float CurrentHealth => _currentHealth;
        public float HealthPercent => _currentHealth / _currentStats.maxHealth;
        public float CurrentExp => _currentExp;
        public float ExpPercent => _currentExp / _expToNextLevel;
        public bool IsDead => _currentState == HeroState.Dead;

        public System.Action<Hero> OnLevelUp;
        public System.Action<Hero> OnDeath;
        public System.Action<float> OnHealthChanged;
        public System.Action<float> OnExpChanged;
        public System.Action<string> OnSkillUsed;
        public System.Action<string> OnSkillReady;

        private void Awake()
        {
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
            if (_spriteRenderer == null) _spriteRenderer = GetComponentInChildren<SpriteRenderer>();
        }

        public void Initialize(HeroData data)
        {
            _heroData = data;
            _currentStats = data.baseStats;
            _currentHealth = _currentStats.maxHealth;
            _currentLevel = 1;
            _currentExp = 0f;
            _currentState = HeroState.Idle;

            foreach (var skill in _heroData.skills)
            {
                _skillCooldowns[skill.skillName] = 0f;
            }
        }

        private void Update()
        {
            if (_currentState == HeroState.Dead) return;

            UpdateCooldowns();
            UpdateMovement();
            UpdateAttack();
            UpdateHealthRegen();
        }

        private void UpdateCooldowns()
        {
            List<string> skills = new List<string>(_skillCooldowns.Keys);
            foreach (var skillName in skills)
            {
                if (_skillCooldowns[skillName] > 0)
                {
                    _skillCooldowns[skillName] -= Time.deltaTime;
                    if (_skillCooldowns[skillName] <= 0)
                    {
                        _skillCooldowns[skillName] = 0;
                        OnSkillReady?.Invoke(skillName);
                    }
                }
            }
        }

        private void UpdateMovement()
        {
            if (!_isMoving) return;

            Vector3 direction = (_targetPosition - transform.position).normalized;
            transform.position += direction * _moveSpeed * Time.deltaTime;

            if (_spriteRenderer != null)
            {
                _spriteRenderer.flipX = direction.x < 0;
            }

            float distance = Vector3.Distance(transform.position, _targetPosition);
            if (distance <= _arrivalThreshold)
            {
                _isMoving = false;
                _currentState = HeroState.Idle;

                if (_animator != null)
                {
                    _animator.SetBool("IsMoving", false);
                }
            }
        }

        private void UpdateAttack()
        {
            if (_currentState != HeroState.Idle) return;

            if (_currentTarget == null || _currentTarget.IsDead)
            {
                FindTarget();
            }

            if (_currentTarget != null && _attackCooldown <= 0)
            {
                Attack();
            }

            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        private void UpdateHealthRegen()
        {
            if (_currentStats.healthRegen > 0 && _currentHealth < _currentStats.maxHealth)
            {
                _currentHealth += _currentStats.healthRegen * Time.deltaTime;
                if (_currentHealth > _currentStats.maxHealth)
                {
                    _currentHealth = _currentStats.maxHealth;
                }
                OnHealthChanged?.Invoke(_currentHealth);
            }
        }

        public void MoveTo(Vector3 position)
        {
            _targetPosition = position;
            _isMoving = true;
            _currentState = HeroState.Moving;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", true);
            }
        }

        public void StopMoving()
        {
            _isMoving = false;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", false);
            }
        }

        private void FindTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            _currentTarget = spawner.GetClosestEnemy(transform.position, _currentStats.attackRange);
        }

        private void Attack()
        {
            if (_currentTarget == null) return;

            _currentState = HeroState.Attacking;
            _attackCooldown = 1f / _currentStats.attackSpeed;

            if (_animator != null)
            {
                _animator.SetTrigger("Attack");
            }

           // 在第211行和第257行添加转换
            _currentTarget.TakeDamage(Mathf.RoundToInt(_currentStats.attackDamage), DamageType.Physical);

            _currentState = HeroState.Idle;
        }

        public bool UseSkill(int skillIndex)
        {
            if (skillIndex < 0 || skillIndex >= _heroData.skills.Length) return false;

            HeroData.HeroSkill skill = _heroData.skills[skillIndex];

            if (_skillCooldowns[skill.skillName] > 0) return false;

            _skillCooldowns[skill.skillName] = skill.cooldown;
            _currentState = HeroState.UsingSkill;

            if (_animator != null)
            {
                _animator.SetTrigger("Skill");
            }

            ExecuteSkill(skill);

            OnSkillUsed?.Invoke(skill.skillName);
            EventBus.Publish(new SkillUsedEvent { SkillName = skill.skillName });

            _currentState = HeroState.Idle;
            return true;
        }

        private void ExecuteSkill(HeroData.HeroSkill skill)
        {
            if (skill.effectPrefab != null)
            {
                Instantiate(skill.effectPrefab, transform.position, Quaternion.identity);
            }

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, skill.effectRadius);

            foreach (var enemy in enemiesInRange)
            {
                if (enemy != null && !enemy.IsDead)
                {
                    // 在第211行和第257行添加转换
enemy.TakeDamage(Mathf.RoundToInt(skill.effectValue), DamageType.Magic);
                }
            }
        }

        public void TakeDamage(float damage)
        {
            if (_currentState == HeroState.Dead) return;

            float actualDamage = damage * (1f - _currentStats.armor / 100f);
            _currentHealth -= actualDamage;

            OnHealthChanged?.Invoke(_currentHealth);

            if (_animator != null)
            {
                _animator.SetTrigger("Hit");
            }

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        public void Heal(float amount)
        {
            _currentHealth += amount;
            if (_currentHealth > _currentStats.maxHealth)
            {
                _currentHealth = _currentStats.maxHealth;
            }
            OnHealthChanged?.Invoke(_currentHealth);
        }

        public void AddExp(float exp)
        {
            _currentExp += exp;
            OnExpChanged?.Invoke(_currentExp);

            while (_currentExp >= _expToNextLevel)
            {
                LevelUp();
            }
        }

        private void LevelUp()
        {
            _currentExp -= _expToNextLevel;
            _currentLevel++;
            _expToNextLevel *= 1.5f;

            _currentStats.maxHealth *= 1.1f;
            _currentStats.attackDamage *= 1.1f;
            _currentHealth = _currentStats.maxHealth;

            OnLevelUp?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetTrigger("LevelUp");
            }
        }

        private void Die()
        {
            _currentState = HeroState.Dead;
            OnDeath?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetBool("IsDead", true);
            }
        }

        public void Revive()
        {
            _currentHealth = _currentStats.maxHealth;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsDead", false);
            }
        }

        public float GetSkillCooldown(string skillName)
        {
            return _skillCooldowns.TryGetValue(skillName, out float cd) ? cd : 0f;
        }

        public float GetSkillCooldownPercent(string skillName)
        {
            foreach (var skill in _heroData.skills)
            {
                if (skill.skillName == skillName)
                {
                    return GetSkillCooldown(skillName) / skill.cooldown;
                }
            }
            return 0f;
        }
    }
}

using UnityEngine;
using UnityEngine.EventSystems;
using TowerDefense.Data;

namespace TowerDefense.Hero
{
    public class HeroController : MonoBehaviour
    {
        [Header("Hero")]
        [SerializeField] private Hero _hero;
        [SerializeField] private HeroData _heroData;

        [Header("Movement Settings")]
        [SerializeField] private bool _useClickMovement = true;
        [SerializeField] private LayerMask _groundLayer;

        [Header("Skill Keys")]
        [SerializeField] private KeyCode _skill1Key = KeyCode.Q;
        [SerializeField] private KeyCode _skill2Key = KeyCode.W;
        [SerializeField] private KeyCode _skill3Key = KeyCode.E;

        private Camera _mainCamera;

        private void Awake()
        {
            _mainCamera = Camera.main;

            if (_hero == null)
            {
                _hero = GetComponent<Hero>();
            }
        }

        private void Start()
        {
            if (_hero != null && _heroData != null)
            {
                _hero.Initialize(_heroData);
            }
        }

        private void Update()
        {
            if (_hero == null || _hero.IsDead) return;

            HandleMovement();
            HandleSkills();
        }

        private void HandleMovement()
        {
            if (!_useClickMovement) return;

            if (Input.GetMouseButtonDown(1) && !EventSystem.current.IsPointerOverGameObject())
            {
                Ray ray = _mainCamera.ScreenPointToRay(Input.mousePosition);
                RaycastHit2D hit = Physics2D.Raycast(ray.origin, ray.direction, Mathf.Infinity, _groundLayer);

                if (hit.collider != null)
                {
                    _hero.MoveTo(hit.point);
                }
                else
                {
                    Vector3 worldPosition = _mainCamera.ScreenToWorldPoint(Input.mousePosition);
                    worldPosition.z = 0;
                    _hero.MoveTo(worldPosition);
                }
            }
        }

        private void HandleSkills()
        {
            if (_heroData == null || _heroData.skills == null) return;

            if (Input.GetKeyDown(_skill1Key) && _heroData.skills.Length > 0)
            {
                _hero.UseSkill(0);
            }
            else if (Input.GetKeyDown(_skill2Key) && _heroData.skills.Length > 1)
            {
                _hero.UseSkill(1);
            }
            else if (Input.GetKeyDown(_skill3Key) && _heroData.skills.Length > 2)
            {
                _hero.UseSkill(2);
            }
        }

        public void UseSkillByIndex(int index)
        {
            if (_hero != null)
            {
                _hero.UseSkill(index);
            }
        }

        public void SetHeroData(HeroData data)
        {
            _heroData = data;
            if (_hero != null)
            {
                _hero.Initialize(_heroData);
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.Enemy
{
    public class EnemyHealth : MonoBehaviour
    {
        [Header("Health Settings")]
        [SerializeField] private int _maxHealth = 100;
        [SerializeField] private int _goldReward = 10;

        [Header("UI Settings")]
        [SerializeField] private GameObject _healthBarPrefab;
        [SerializeField] private Vector3 _healthBarOffset = new Vector3(0, 1, 0);

        private int _currentHealth;
        private Slider _healthBarSlider;
        private Transform _healthBarTransform;

        public int CurrentHealth => _currentHealth;
        public int MaxHealth => _maxHealth;
        public float HealthPercentage => (float)_currentHealth / _maxHealth;

        public System.Action<int, int> OnHealthChanged;
        public System.Action OnDeath;

        private void Awake()
        {
            _currentHealth = _maxHealth;

            if (_healthBarPrefab != null)
            {
                CreateHealthBar();
            }
        }

        public void Initialize(int maxHealth, int goldReward)
        {
            _maxHealth = maxHealth;
            _currentHealth = maxHealth;
            _goldReward = goldReward;

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        private void CreateHealthBar()
        {
            Canvas canvas = FindObjectOfType<Canvas>();
            if (canvas == null) return;

            GameObject healthBarObj = Instantiate(_healthBarPrefab);
            healthBarObj.transform.SetParent(canvas.transform, false);

            _healthBarTransform = healthBarObj.transform;
            _healthBarSlider = healthBarObj.GetComponentInChildren<Slider>();

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        public void TakeDamage(int damage)
        {
            TakeDamage(damage, DamageType.Physical);
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            _currentHealth -= damage;
            _currentHealth = Mathf.Max(0, _currentHealth);

            // 触发血量变化事件
            OnHealthChanged?.Invoke(_currentHealth, _maxHealth);

            UpdateHealthBar();

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        private void UpdateHealthBar()
        {
            if (_healthBarTransform != null && _healthBarSlider != null)
            {
                _healthBarSlider.value = _currentHealth;

                Vector3 worldPos = Camera.main.WorldToScreenPoint(transform.position + _healthBarOffset);
                _healthBarTransform.position = worldPos;
            }
        }

        private void Die()
        {
            Destroy(_healthBarTransform?.gameObject);
            // 触发死亡事件
            OnDeath?.Invoke();
            SendMessage("OnDeath", SendMessageOptions.DontRequireReceiver);
        }

        private void OnDestroy()
        {
            Destroy(_healthBarTransform?.gameObject);
        }
    }
}

