using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public enum TowerState
    {
        Idle,
        Targeting,
        Attacking,
        Upgrading,
        Selling
    }

    public class Tower : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] protected TowerData _towerData;
        [SerializeField] protected TowerAttack _attack;
        [SerializeField] protected Animator _animator;
        [SerializeField] protected Transform _rotatePart;
        [SerializeField] protected SpriteRenderer _spriteRenderer;

        [Header("Visual")]
        [SerializeField] protected GameObject _rangeIndicator;
        [SerializeField] protected Color _rangeColor = new Color(0, 1, 0, 0.3f);

        protected int _currentLevel = 1;
        protected TowerState _currentState = TowerState.Idle;
        protected TowerData.TowerStats _currentStats;
        protected Enemy.Enemy _currentTarget;
        protected TowerSlot _slot;

        public TowerData Data => _towerData;
        public int CurrentLevel => _currentLevel;
        public TowerState State => _currentState;
        public Enemy.Enemy CurrentTarget => _currentTarget;
        public TowerData.TowerStats CurrentStats => _currentStats;
        public TowerSlot Slot => _slot;
        public bool IsMaxLevel => _currentLevel >= _towerData.levels.Length;

        public System.Action<Tower> OnUpgrade;
        public System.Action<Tower> OnSell;
        public System.Action<Enemy.Enemy> OnTargetAcquired;
        public System.Action OnTargetLost;

        protected virtual void Awake()
        {
            if (_attack == null) _attack = GetComponent<TowerAttack>();
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
        }

        public virtual void Initialize(TowerData data, TowerSlot slot)
        {
            _towerData = data;
            _slot = slot;
            _currentLevel = 1;
            _currentStats = data.levels[0];
            _currentState = TowerState.Idle;

            if (_attack != null)
            {
                _attack.Initialize(this);
            }

            UpdateRangeIndicator();
        }

        protected virtual void Update()
        {
            if (_currentState == TowerState.Upgrading || _currentState == TowerState.Selling)
                return;

            FindTarget();

            if (_currentTarget != null)
            {
                RotateTowardsTarget();
                Attack();
            }
        }

        protected virtual void FindTarget()
        {
            float actualAttackRange = _currentStats.attackRange;

            if (_currentTarget != null && !_currentTarget.IsDead)
            {
                float distance = Vector3.Distance(transform.position, _currentTarget.transform.position);
                if (distance <= actualAttackRange)
                {
                    return;
                }
            }

            _currentTarget = FindBestTarget();

            if (_currentTarget != null)
            {
                _currentState = TowerState.Targeting;
                OnTargetAcquired?.Invoke(_currentTarget);
            }
            else
            {
                _currentState = TowerState.Idle;
                OnTargetLost?.Invoke();
            }
        }

        protected virtual Enemy.Enemy FindBestTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null)
            {
                Debug.LogError("EnemySpawner not found!");
                return null;
            }

            float actualAttackRange = _currentStats.attackRange;
            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, actualAttackRange);

            if (enemiesInRange.Count == 0) return null;

            Enemy.Enemy bestTarget = null;
            float bestPriority = float.MinValue;

            foreach (var enemy in enemiesInRange)
            {
                if (enemy == null || enemy.IsDead) continue;

                float priority = CalculateTargetPriority(enemy);
                if (priority > bestPriority)
                {
                    bestPriority = priority;
                    bestTarget = enemy;
                }
            }

            return bestTarget;
        }

        protected virtual float CalculateTargetPriority(Enemy.Enemy enemy)
        {
            EnemyMovement movement = enemy.GetComponent<EnemyMovement>();
            if (movement != null)
            {
                return movement.GetProgressPercent();
            }
            return 0f;
        }

        protected virtual void RotateTowardsTarget()
        {
            if (_rotatePart == null || _currentTarget == null) return;

            Vector3 direction = _currentTarget.transform.position - _rotatePart.position;
            float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg;
            Quaternion targetRotation = Quaternion.AngleAxis(angle, Vector3.forward);
            _rotatePart.rotation = Quaternion.Slerp(_rotatePart.rotation, targetRotation, 10f * Time.deltaTime);
        }

        protected virtual void Attack()
        {
            if (_attack == null) return;

            if (_attack.CanAttack())
            {
                _currentState = TowerState.Attacking;
                _attack.Attack(_currentTarget);
            }
        }

        public virtual bool Upgrade()
        {
            if (IsMaxLevel) return false;

            TowerData.TowerStats nextLevelStats = _towerData.levels[_currentLevel];
            if (!GameManager.Instance.SpendGold(nextLevelStats.upgradeCost)) return false;

            _currentLevel++;
            _currentStats = nextLevelStats;

            if (_animator != null)
            {
                _animator.SetTrigger("Upgrade");
            }

            UpdateRangeIndicator();
            OnUpgrade?.Invoke(this);
            EventBus.Publish(new TowerUpgradedEvent { Tower = gameObject, Level = _currentLevel });

            return true;
        }

        public virtual void Sell()
        {
            Debug.Log($"📤 Tower.Sell() called for {gameObject.name}");
            Debug.Log($"   sellValue: {_currentStats.sellValue}");
            Debug.Log($"   _slot: {_slot != null}");

            int sellValue = _currentStats.sellValue;
            GameManager.Instance.AddGold(sellValue);
            Debug.Log($"   ✅ Added {sellValue} gold");

            OnSell?.Invoke(this);
            EventBus.Publish(new TowerSoldEvent { Tower = gameObject, Refund = sellValue });

            if (_slot != null)
            {
                _slot.RemoveTower();
                Debug.Log($"   ✅ Called _slot.RemoveTower()");
            }

            Destroy(gameObject);
            Debug.Log($"   ✅ Tower destroyed");
        }

        public int GetUpgradeCost()
        {
            if (IsMaxLevel) return 0;
            return _towerData.levels[_currentLevel].upgradeCost;
        }

        public int GetSellValue()
        {
            return _currentStats.sellValue;
        }

        public void ShowRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(true);
            }
        }

        public void HideRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(false);
            }
        }

        protected void UpdateRangeIndicator()
        {
            if (_rangeIndicator != null)
            {
                float scale = _currentStats.attackRange * 2f;
                _rangeIndicator.transform.localScale = new Vector3(scale, scale, 1f);
            }
        }

        private void OnDrawGizmosSelected()
        {
            if (_towerData != null && _currentStats.attackRange > 0)
            {
                Gizmos.color = _rangeColor;
                Gizmos.DrawWireSphere(transform.position, _currentStats.attackRange);
            }
        }
    }
}

using System.Collections;
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class TowerAttack : MonoBehaviour
    {
        [Header("Attack Settings")]
        [SerializeField] private Transform _firePoint;
        [SerializeField] private bool _autoFire = true;

        protected Tower _tower;
        protected float _attackCooldown = 0f;
        protected bool _canAttack = true;

        public bool CanAttackValue => _canAttack && _attackCooldown <= 0f;

        public virtual void Initialize(Tower tower)
        {
            _tower = tower;
            _attackCooldown = 0f;
        }

        protected virtual void Update()
        {
            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        public bool CanAttack()
        {
            return _attackCooldown <= 0f && _tower.CurrentTarget != null;
        }

        public virtual void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            switch (_tower.Data.towerType)
            {
                case TowerType.Archer:
                    FireProjectile(target);
                    break;
                case TowerType.Mage:
                    FireMagicAttack(target);
                    break;
                case TowerType.Barracks:
                    SpawnSoldiers(target);
                    break;
                case TowerType.Artillery:
                    FireExplosive(target);
                    break;
                case TowerType.Sword:
                    FirePierceProjectile(target);
                    break;
            }

            _attackCooldown = 1f / stats.attackSpeed;

            if (_tower.GetComponent<Animator>() != null)
            {
                _tower.GetComponent<Animator>().SetTrigger("Attack");
            }
        }

        protected virtual void FireProjectile(Enemy.Enemy target)
        {
            Debug.Log($"FireProjectile called");
            Debug.Log($"Projectile prefab: " + _tower.Data.projectilePrefab);
            Debug.Log($"FirePoint: " + _firePoint);

            if (_tower.Data.projectilePrefab == null || _firePoint == null)
            {
                if (_tower.Data.projectilePrefab == null)
                {
                    Debug.LogError("Projectile prefab is null!");
                }
                return;
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Physical);
            }
        }

        protected virtual void FireMagicAttack(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Magic);
            }
        }

        protected virtual void FireExplosive(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(
                    target,
                    _tower.CurrentStats.damage,
                    DamageType.Explosion,
                    _tower.CurrentStats.splashRadius
                );
            }
        }

        protected virtual void SpawnSoldiers(Enemy.Enemy target)
        {
        }

        protected virtual void FirePierceProjectile(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            int pierceCount = stats.pierceCount;
            if (pierceCount <= 0)
            {
                int towerLevel = _tower.CurrentLevel;
                pierceCount = towerLevel switch
                {
                    1 => 3,
                    2 => 5,
                    3 => 7,
                    _ => 3
                };
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, stats.damage, DamageType.Physical, 0f, pierceCount);
            }
        }

        public void SetFirePoint(Transform firePoint)
        {
            _firePoint = firePoint;
        }
    }
}

